 main()&#123;//	freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);//	freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);		freopen(&quot;number.in&quot;, &quot;r&quot;, stdin);	freopen(&quot;number.out&quot;, &quot;w&quot;, stdout);//	T=read();//	while(T--) &#123;////	&#125;	n=read(); m=read(); init(2000000); 	prim(2000000); 	lstlim=0; ans=1; 	for(d=m; d&gt;=1; --d) &#123;		lim=m/d; //		if(lim==lstlim) &#123;//			f[d]=f[d+1]; g[d]=g[d+1];//		&#125;//		else &#123;			f[d]=pw(d, pw(lim, n, mo-1)); 			for(auto p : z) &#123;				if(p&gt;lim) break; //				printf(&quot;%lld : \n&quot;, p); 				for(c=0, P=1; P&lt;=lim; P*=p, ++c) &#123;					S[c]=pw(lim-lim/(P*p), n, mo-1); //					printf(&quot;S %lld : %lld %lld\n&quot;, c, S[c], lim-lim/(P+1)); 				&#125;				for(c=1, P=p; P&lt;=lim; P*=p, ++c) &#123;					s[c]=S[c]-S[c-1]; Mod(s[c], mo-1); //					printf(&quot;s %lld : %lld\n&quot;, c, s[c]); 					Mul(f[d], pw(P, s[c])); //					printf(&quot;%lld\n&quot;, f[d]); 				&#125;			&#125;			g[d]=f[d]; 			for(D=2*d; D&lt;=m; D+=d) Mul(g[d], pw(g[D], mo-2)); //		&#125;//		lstlim=lim; //		printf(&quot;%lld : %lld %lld %lld\n&quot;, d, f[d], g[d], pw(g[d], d)); 		Mul(ans, pw(g[d], d)); 	&#125;	Mod(ans); 	printf(&quot;%lld&quot;, ans); 	return 0;&#125;

