Splay的两个关键函数，rotate和splay
rotate就是正常的旋转。
splay(x,target)表示把x旋转为target的子节点
这里需要分讨，对于x的父亲y和祖父z


若 z = target， 则直接转x


若 x 与 y 方向相同，先转y，后转x


若 x 与 y 方向不同，转2次x


对于每一个操作，只要访问一个点，都要splay一次。而且要更新访问的最下面的点。
同时对结构改变时要考虑会不会搞到0号点。
struct Splay &#123;	int son[N][2], fa[N], cnt[N], w[N], a[N], root, tot; 	int ls(int x) &#123; return son[x][0]; &#125;	int rs(int x) &#123; return son[x][1]; &#125;	int zh(int x) &#123; return rs(fa[x]) == x; &#125;	void push_up(int x) &#123; if(x) w[x] = cnt[x] + w[ls(x)] + w[rs(x)]; &#125;	void print(int x) &#123;		if(!x) return ; 		printf(&quot;%d [%d] -&gt; [%d %d]\n&quot;, a[x], w[x], a[ls(x)], a[rs(x)]); 		print(ls(x)); print(rs(x)); 		if(x == root) printf(&quot;----------------\n&quot;); 	&#125;	void rotate(int x) &#123;		int y = fa[x], z = fa[y]; 		int k = zh(x), w = son[x][k ^ 1]; 		if(z) son[z][zh(y)] = x, fa[x] = z; else fa[x] = 0; 		if(w) son[y][k] = w, fa[w] = y; else son[y][k] = 0; 		son[x][k ^ 1] = y; fa[y] = x; 		push_up(y); push_up(x); 	&#125;	void splay(int x, int target = 0) &#123;		while(fa[x] != target) &#123;			int y = fa[x], z = fa[y]; 			if(z != target) &#123;				if(zh(x) == zh(y)) rotate(y); 				else rotate(x); 			&#125;			rotate(x); 		&#125;		if(!target) root = x; 	&#125;	void insert(int x) &#123;		int now = root, las = 0; 		while(now &amp;&amp; a[now] != x) 			las = now, now = son[now][x &gt; a[now]]; 		if(!now) &#123;			now = ++tot; 			if(las) son[las][x &gt; a[las]] = now; 			fa[now] = las; a[now] = x; 		&#125;		++cnt[now]; ++w[now]; 		splay(now); 	&#125;	int find_last(int x) &#123;		int now = root, ans = 0, las = 0; 		while(now) &#123;			las = now; 			if(a[now] &gt;= x) now = ls(now); 			else ans = now, now = rs(now); 		&#125;		splay(las); 		return ans; 	&#125;	int find_next(int x) &#123;		int now = root, ans = 0, las = 0; 		while(now) &#123;			las = now; 			if(a[now] &lt;= x) now = rs(now); 			else ans = now, now = ls(now); 		&#125;		splay(las); 		return ans; 	&#125;	int cha_x_rank(int x) &#123;		int u = find_last(x + 1); splay(u);		int ans = w[u] - w[rs(u)]; 	 		if(a[u] == x) ans -= cnt[u]; 		return ans + 1; 	&#125;	int cha_rank(int now) &#123;		int x = root, las = 0; 		while(x) &#123;			if(w[ls(x)] &gt;= now) x = ls(x); 			else if(w[ls(x)] + cnt[x] &gt;= now) return splay(x), x; 			else now -= (w[ls(x)] + cnt[x]), x = rs(x); 		&#125;		assert(x); return 0; 	&#125;	void join(int x, int y) &#123;		fa[x] = fa[y] = 0; 		while(rs(x)) x = rs(x); 		if(x) splay(x), son[x][1] = y, fa[y] = x;		else root = y; 		push_up(x); 	&#125;	void del(int x) &#123;		int u = find_last(x + 1); splay(u); 		if(cnt[u] &gt; 1) return --cnt[u], --w[u], void(); 		join(ls(u), rs(u)); 	&#125;&#125;T;

