ABC 461 F（搜索、计数）
不难发现，合法的状态数（在不考虑排列的情况下）必然不多，于是我们可以预处理因子后直接搜索，搜索过程记录当前有多少个数和数的和。最后拿和乘以排列数即可。
但直接这样子做会T掉，我们尝试把数从大往小排序，然后就过了
#include&lt;bits/stdc++.h&gt;using namespace std;#ifdef LOCAL #define debug(...) fprintf(stdout, ##__VA_ARGS__)#else #define debug(...) void(0)#endif#define int long longinline int read()&#123;int x=0,f=1;char ch=getchar();while(ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if(ch==&#x27;-&#x27;)f=-1;ch=getchar();&#125;while(ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=(x&lt;&lt;1)+(x&lt;&lt;3)+(ch^48);ch=getchar();&#125;return x*f;&#125;#define Z(x) (x)*(x)#define pb push_back#define fi first#define se second//#define M#define mo 998244353#define N 2010int n, m, i, j, k, T;int fac[N], ans; unordered_map&lt;int, bool&gt;mp;  vector&lt;int&gt;v, v2; void dfs(int n, int stp, int sum, int i) &#123;		for(; i &lt; m; ++i) &#123;		if(n == v[i]) &#123;			ans += (sum + n) % mo * fac[stp + 1] % mo; 			ans %= mo; 		&#125;		if(n % v[i] == 0) &#123;			dfs(n / v[i], stp + 1, sum + v[i], i + 1); 		&#125;	&#125;&#125;signed main()&#123;	#ifdef LOCAL	  freopen(&quot;in.txt&quot;, &quot;r&quot;, stdin);	  freopen(&quot;out.txt&quot;, &quot;w&quot;, stdout);	#endif//	srand(time(NULL));//	T = read();//	while(T--) &#123;////	&#125;	n = read(); 	for(i = fac[0] = 1; i &lt;= 2000; ++i) 		fac[i] = fac[i - 1] * i % mo; 	for(i = 1; i * i &lt;= n; ++i) &#123;		if(n % i == 0 &amp;&amp; i * i != n) v.pb(i), v.pb(n / i); 		else if(n % i == 0) v.pb(i);  	&#125; 	m = v.size(); 	sort(v.begin(), v.end()); 	reverse(v.begin(), v.end()); 	dfs(n, 0, 0, 0);  	printf(&quot;%lld\n&quot;, ans); 	return 0;&#125;
ABC 460 F（树、dfs序、线段树）

题目本质是动态求树的直径。
动态求树的直径是套路，先跑出dfn序，然后用线段树维护即可。
具体得，我们要维护区间最深点、区间最浅点，区间答案，区间左+中最大值，区间中+右最大值。
用这几个就能拼凑出答案了。
